challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The RTPEngine is experiencing high packet loss, leading to severe media quality degradation for VoNR calls. This is the most likely cause of the user-facing impact.",
      "primary_suspect_nf": "rtpengine",
      "probes": [
        {
          "tool": "measure_rtt",
          "args_hint": "from: upf, to: rtpengine",
          "expected_if_hypothesis_holds": "Low RTT and no packet loss. This would isolate the packet loss to the rtpengine process itself, not the underlying network path to it.",
          "falsifying_observation": "High RTT or significant packet loss. This would suggest the problem is in the transport network between the UPF and RTPEngine, not within the RTPEngine container."
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from: nr_gnb, to: upf",
          "expected_if_hypothesis_holds": "Low RTT and no packet loss, indicating the RAN-to-core data plane is healthy.",
          "falsifying_observation": "High RTT or significant packet loss. This would suggest the media degradation originates upstream from the IMS media plane, likely in the RAN or 5G core data plane."
        },
        {
          "tool": "check_process_listeners",
          "args_hint": "container: rtpengine",
          "expected_if_hypothesis_holds": "The rtpengine process is listening on its configured UDP port range for media.",
          "falsifying_observation": "The rtpengine process has no open UDP ports for media. This would mean it cannot receive any media, falsifying the 'high packet loss' hypothesis in favor of a total connectivity failure."
        }
      ],
      "notes": "The hypothesis points to packet processing inside rtpengine. These probes test the external factors that could cause the same symptom: network loss on the path to/from rtpengine, or a failure of the process to listen for traffic at all."
    },
    {
      "hypothesis_id": "h2",
      "hypothesis_statement": "The I-CSCF is having issues communicating with the HSS, as indicated by increased response times and timeouts for Diameter messages. This could be due to a network issue between the two components, or a problem specific to the I-CSCF's Diameter stack.",
      "primary_suspect_nf": "icscf",
      "probes": [
        {
          "tool": "measure_rtt",
          "args_hint": "from: icscf, to: pyhss",
          "expected_if_hypothesis_holds": "High RTT (>100ms) or packet loss, confirming a network issue on the Cx interface.",
          "falsifying_observation": "Clean RTT (<5ms) and no packet loss. This would indicate the network is healthy, pointing the problem to the application-layer Diameter stacks on either icscf or pyhss."
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from: scscf, to: pyhss",
          "expected_if_hypothesis_holds": "RTT is also high. While this doesn't falsify the original 'icscf to hss' observation, it makes the 'icscf is the problem' part of the hypothesis less likely.",
          "falsifying_observation": "Clean RTT (<5ms) from scscf to pyhss. This isolates the problem to the icscf-to-pyhss path specifically, strengthening the hypothesis that icscf is the source of the issue."
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from: icscf, to: scscf",
          "expected_if_hypothesis_holds": "Clean RTT (<5ms) and no packet loss. The hypothesis is specific to the HSS link.",
          "falsifying_observation": "High RTT or packet loss. This would suggest a broader networking issue with the I-CSCF, not one confined to its HSS communication."
        }
      ],
      "notes": "This plan focuses on falsifying the 'I-CSCF is the problem' hypothesis by triangulating the observed network problem (h2). Probes measure RTT from another source to the same destination (pyhss) and from the same source (icscf) to another destination to isolate the fault."
    },
    {
      "hypothesis_id": "h3",
      "hypothesis_statement": "There is a general degradation of the IMS signaling plane, causing call setup failures. The lack of active dialogs on the P-CSCF supports this, but the evidence is not specific to a single component.",
      "primary_suspect_nf": "pcscf",
      "probes": [
        {
          "tool": "get_network_status",
          "args_hint": "container: pcscf",
          "expected_if_hypothesis_holds": "Container is in a 'running' state.",
          "falsifying_observation": "Container is in an 'exited' or other non-running state. This would be a root cause, not 'degradation'."
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from: pcscf, to: icscf",
          "expected_if_hypothesis_holds": "High RTT or packet loss, consistent with 'general degradation'.",
          "falsifying_observation": "Clean RTT (<5ms) and no packet loss. This makes a network-level issue between P-CSCF and I-CSCF unlikely, suggesting the problem is at the application layer within one of the components."
        },
        {
          "tool": "get_nf_metrics",
          "args_hint": "Check for pcscf SIP error metrics, e.g. kamailio_s_core_fwd_failure_counter",
          "expected_if_hypothesis_holds": "SIP error counters on the P-CSCF are elevated, showing it is actively failing to process signaling messages.",
          "falsifying_observation": "All P-CSCF SIP error counters are zero. This would strongly suggest the P-CSCF is not receiving any signaling traffic to reject, pointing the root cause upstream (e.g., UPF, gNB, or UE)."
        }
      ],
      "notes": "The hypothesis is vague. This plan aims to make it concrete by checking three distinct failure modes for the primary suspect, P-CSCF: is it down, is its network connectivity impaired, or is it failing internally at the application level?"
    }
  ]
}

